// variabili globali dell'applicazione
var currentHash="";
var polygons=[];
var labels=[];

var geohash = require('ngeohash');

var base32chars="0123456789bcdefghjkmnpqrstuvwxyz";

var geoHashLabel = L.Class.extend({
    initialize : function (bounds) {   
        this._bounds=bounds;
        this._latlng=bounds.getCenter();
    },

    onAdd: function (map) {
        this._map=map;
        this._el = L.DomUtil.create('div','geohash-label leaflet-zoom-hide');
        map.getPanes().overlayPane.appendChild(this._el);
        
        map.on('viewreset',this._reset,this);

        this._reset();
        this._el.innerHTML=this._string;
    },

    setString: function (string) {
        this._string=string;
    },

    setColor: function(color) {
        this._color=color;
    },

    onRemove: function(map) {
        map.getPanes().overlayPane.removeChild(this._el);
        map.off('viewreset',this._reset,this);
    },

    _reset: function () {
        
        var pos = this._map.latLngToLayerPoint(this._latlng),
            ne = this._map.latLngToLayerPoint(this._bounds._northEast),
            sw = this._map.latLngToLayerPoint(this._bounds._southWest),

            container = this._el;
        var fontsize=(ne.x-sw.x)/this._string.length;
        $('.geohash-label').css('font',fontsize+'px "Helvetica Neue", Arial, Helvetica, sans-serif');
        L.DomUtil.setPosition(container,pos);
    }
});

var geoHashControl3 = L.Control.extend({
    options: {
        position: 'bottomleft'
    },

    onAdd: function (map) {
        // create the control container with a particular class name
        var container = L.DomUtil.create('div', 'geohashinfo');
        container.innerHTML = '<i class="fa fa-arrows fa-2x" id="neighbors"></i>';

        return container;
    }
});

var geoHashControl = L.Control.extend({
    options: {
        position: 'bottomleft'
    },

    onAdd: function (map) {
        // create the control container with a particular class name
        var container = L.DomUtil.create('div', 'geohashinfo');
        container.innerHTML = '<i class="fa fa-globe fa-2x" id="globe"></i>';

        return container;
    }
});

var geoHashControl2 = L.Control.extend({
    options: {
        position: 'bottomleft'
    },

    onAdd: function (map) {
        // create the control container with a particular class name
        var container = L.DomUtil.create('div', 'geohashinfo');
        container.innerHTML = '<div id="gh"></div><i class="fa fa-arrow-left fa-2x" id="shortener"></i>';

        return container;
    }
});

map.addControl(new geoHashControl());
map.addControl(new geoHashControl2());
map.addControl(new geoHashControl3());


$('#neighbors').click(function() {
    var neighbors=geohash.neighbors(currentHash);
    
    clearPolys();
    createPolygon(currentHash,'blue');
    for (var n in neighbors) {
        createPolygon(neighbors[n],'orange');
    }
    
});

$('#globe').click(function() {
    $('#gh').html('');
    currentHash="";
    clearPolys();
    showSubHash('');
});

$('#shortener').click(function() {
    var new_hash=currentHash.slice(0,-1);
    currentHash=new_hash;
      $('#gh').html(' '+new_hash);
        
        clearPolys();
        showSubHash(new_hash);
        
});

function clearPolys() {

    for (var i in polygons) {
        map.removeLayer(polygons[i]);
    }

    for (var i in labels) {
        map.removeLayer(labels[i]);
    }
}

function createPolygon(str, color) {
 if (color === undefined ) color = "blue";
 var latlon = geohash.decode_bbox(str);
 var a = [ 
        [latlon[0],latlon[1]],
        [latlon[0],latlon[3]],
        [latlon[2],latlon[3]],
        [latlon[2], latlon[1]]
        ];
 var poly =   new L.polygon(a, { weight: 1 , color: color }).addTo(map);
 poly.geohash=str;
 polygons.push(poly);
 poly.on('mouseover',mouseOverListener);
 poly.on('mouseout',mouseOutListener);
 poly.on('click',clickEventListener);

var label = new geoHashLabel(poly.getBounds());

label.setString(str);
label.setColor(color);
map.addLayer(label);
labels.push(label);

}

function showSubHash(initial_str) {

if (initial_str.length >=8 )  {
    clearPolys(); 
    createPolygon(initial_str);

} else {

for (var i =0 ; i< base32chars.length ; i++) {
    var new_str=initial_str+base32chars.charAt(i);
    
    
    createPolygon(new_str);
  

}
}

}

function mouseOutListener() {
     $('#gh').html(currentHash);
}

function mouseOverListener() {
    $('#gh').html(' '+this.geohash);
}

function clickEventListener() {
     $('#gh').html(' '+this.geohash);
        currentHash=this.geohash;
        map.fitBounds(this.getLatLngs());
        
        clearPolys();
        if (this.geohash.length < 9 )  showSubHash(this.geohash);
}
